<template><div><el-alert title="当前展示真实接口数据；运行模式由后端受信任配置决定" type="info" show-icon/><div class="kpis"><div v-for="k in kpis" :key="k.label" class="panel"><small>{{k.label}}</small><strong class="kpi-value" :class="k.tone">{{k.value}}</strong><span>{{k.note}}</span></div></div><div class="grid"><div class="panel"><h3>系统健康状态</h3><div class="health-card"><div class="health-row"><span>API 服务</span><b class="state-chip">运行正常</b></div><div class="health-row"><span>安全规则引擎</span><b class="state-chip">运行正常</b></div><div class="health-row"><span>当前模式</span><b class="state-chip warning">{{zhStatus(session.mode)}}</b></div></div></div><div class="panel"><h3>安全边界</h3><ul><li>确定性规则拥有最终否决权</li><li>不提供任意 Shell 工具</li><li>L3 写操作强制审批、备份、验证与回滚</li><li>外部数据统一标记为不可信数据</li></ul></div><div class="panel chart-panel"><h3>磁盘使用趋势</h3><div ref="chartEl" class="chart"></div><p v-if="chartMessage">{{chartMessage}}</p></div></div></div></template>
<script setup lang="ts">
import{onMounted,ref}from"vue";import{LineChart}from"echarts/charts";import{GridComponent,TooltipComponent}from"echarts/components";import{init,use}from"echarts/core";import{CanvasRenderer}from"echarts/renderers";import{api}from"../api";import{useSession}from"../stores/session";import{zhStatus}from"../status";
use([LineChart,GridComponent,TooltipComponent,CanvasRenderer]);const session=useSession(),chartEl=ref<HTMLElement>(),chartMessage=ref("");const kpis=[{label:"运行模式",value:"安全默认",note:"默认禁止写操作",tone:"accent"},{label:"安全等级",value:"L0 至 L4",note:"由规则引擎判定",tone:""},{label:"MCP 工具",value:"14 个",note:"系统感知工具",tone:""},{label:"审计链",value:"运行正常",note:"事件完整性可验证",tone:"good"}];interface Snapshot{captured_at:string;payload:{data?:{disk?:{used?:number}}}}
onMounted(async()=>{try{await api("/health");const snapshots=await api<Snapshot[]>("/inspections");const points=snapshots.slice().reverse().map(i=>({time:i.captured_at,value:i.payload?.data?.disk?.used})).filter(i=>typeof i.value==="number");if(points.length<3)chartMessage.value="至少完成三次巡检后才会生成趋势";if(chartEl.value)init(chartEl.value).setOption({tooltip:{trigger:"axis"},grid:{left:55,right:24,top:25,bottom:42},xAxis:{type:"category",data:points.map(i=>new Date(i.time).toLocaleTimeString())},yAxis:{type:"value"},series:[{type:"line",smooth:true,data:points.map(i=>i.value),lineStyle:{color:"#2a78d6",width:3},areaStyle:{color:"#dbeafe"}}]})}catch(e){chartMessage.value=e instanceof Error?e.message:"无法连接服务"}});
</script>
